_exceptions_head:"Blokování reklam",adblocker_exceptions_enter_address:"Zadejte adresu webové stránky",adblocker_exceptions_add:"Přidat web",adblocker_exceptions_remove:"Odstranit",adblocker_exceptions_title_list:"Seznam výjimek",adblocker_exceptions_search:"Vyhledávání",faq_title:"FAQ a podpora",faq_item_1_title:"Proč potřebuji VPN?",faq_item_1_description:"Pomocí šifrovací technologie v rámci používání VPN poskytovatel a externí uživatelé internetu nebudou moci vidět, které webové stránky jste navštívili a které webové zdroje jste navštívili. Také se nezobrazí skutečná IP, protože bude nahrazena adresou země, ke které se připojujete přes VPN server. To vám umožní zůstat v bezpečí a zobrazit jakýkoli obsah bez ohledu na vaši polohu.",faq_item_2_title:"Je to zdarma?",faq_item_2_description:"Planet VPN můžete používat zcela zdarma a bez registrace. Pro připojení máte k dispozici 5 oblíbených lokalit bez časového a dopravního omezení.",faq_item_3_title:"Jak používat aplikaci bez omezení?",faq_item_3_description:"Abyste mohli využívat všechny funkce aplikace bez omezení a reklam, potřebujete prémiový přístup. Chcete-li to provést, v hlavním okně aplikace ve spodní části obrazovky klikněte na tlačítko „Získat prémii“ a přihlaste se k odběru.",faq_item_4_title:"Kde je moje heslo?",faq_item_4_description:"Registrace účtu probíhá automaticky, poté bude na zadanou emailovou adresu zaslán email s heslem a potvrzením registrace. Pokud jste e-mail nenašli ve složce Doručená pošta, zkontrolujte složku Spam, možná tam skončil.",faq_item_5_title:"Po nákupu se Premium neobjevilo?",faq_item_5_description:"Pro přístup na Premium servery musíte být v aplikaci autorizováni. Přejděte do nastavení kliknutím na tlačítko v levém horním rohu obrazovky a projděte autorizací.",faq_item_6_title:"Kolik zařízení mohu připojit?",faq_item_6_description:"Pomocí jednoho účtu můžete připojit 10 zařízení současně.",faq_item_7_title:"Proč při připojení klesá rychlost?",faq_item_7_description:"Pokles rychlosti je při používání VPN běžným jevem. K tomu může dojít z důvodu velké vzdálenosti vybraného serveru od vás, problémů na kanálu k serveru nebo současného přetížení serveru. Pokud opětovné připojení nebo změna umístění problém nevyřeší - kontaktujte nás na adrese {link} a my se pokusíme pomoci.",faq_item_8_title:"Sledujete uživatele?",faq_item_8_description:"Naše společnost neuchovává protokoly o online aktivitě uživatelů, datech připojení a IP adresách ani žádné další citlivé údaje o uživatelích. Nejsme povinni sledovat naše uživatele a nejsme povinni spolupracovat s žádnými zpravodajskými agenturami, což nám umožňuje přísně dodržovat zásady ochrany osobních údajů našich klientů.",faq_help_title:"Potřebujete více informací?",faq_help_button:"Zobrazit všechny pokyny",faq_form_title:"Máte ještě otázky?",faq_form_subtitle:"Napište nám e-mail",faq_form_name_placeholder:"Zadejte své jméno",faq_form_email_placeholder:"Zadejte svůj e-mail",faq_form_message_label:"Jak vám můžeme pomoci?",faq_form_button:"Poslat",settings_navigation_head:"Nastavení",settings_autoconnect_title:"Připojte se při spuštění",settings_ad_blocker_title:"Blokovat reklamy",settings_ad_blocker_exceptions:"Výjimky",settings_ad_blocker_tune:"Nastavení",settings_cookies_title:"Odepřít cookies",settings_trackers_title:"Blokové sledovače",settings_history_title:"Neukládat historii",settings_smart_filters_title:"Inteligentní filtry pro webové stránky",settings_smart_filters_exceptions:"Webové stránky",settings_smart_filters_tune:"Správa",settings_warning_title:"Prosím věnujte pozornost",settings_warning_text_1:"Nastavení bude resetováno po aktualizaci rozšíření",settings_warning_text_2:"Vytvořte si účet nebo se přihlaste k uložení nastavení.",sign_in_email:"Zadejte svůj e-mail",sign_in_head:"Zaregistrovat se",sign_in_login:"Přihlásit se",sign_in_password:"Zadejte heslo",sign_in_reset:"Obnovit heslo",smart_filters_head:"Inteligentní filtry pro webové stránky",smart_filters_search:"Vyhledávání",smart_filters_search_empty:"Pro vaše vyhledávání nebyly nalezeny žádné filtry",smart_filters_add:"Přidat web",smart_filters_enter_address:"Zadejte adresu webové stránky",smart_filters_remove:"Odstranit",smart_filters_title_list:"Seznam výjimek",smart_filters_info:"Vytvoření výjimek pro vybrané webové stránky",extension_consent_ads_title:"Reklamy pro uživatele zdarma",extension_consent_ads_1:"Abychom udrželi naši bezplatnou službu konzistentní, vyhrazujeme si právo zobrazit až 3 karty s reklamami každých 24 hodin pro uživatele zdarma. Prémiovým uživatelům se reklamy nezobrazují.",extension_consent_title:"Vaše soukromí je důležité",extension_consent_privacy_1:"Shromažďujeme pouze minimální množství dat potřebných k poskytnutí stabilního připojení VPN a vyššího standardu kvality, například:",extension_consent_privacy_2:"Informace specifické pro zařízení, jako je verze OS, model zařízení a IP adresa pro optimalizaci síťového připojení",extension_consent_privacy_3:"Hlášení o pádech pro zlepšení stability aplikace, která zahrnují anonymní agregovaná data: verze sestavení, trasování zásobníku, datum a čas pádu",extension_consent_privacy_4:"Volitelný e-mail a platební informace, pokud chcete využívat placené předplatné",extension_consent_privacy_5_0:"Podívejte se na naše",extension_consent_privacy_5_1:"Zásady ochrany osobních údajů",extension_consent_privacy_5_2:"kde najdete další podrobnosti o těchto údajích a jejich použití.",extension_consent_confirm:"Souhlasím a pokračovat",extension_conflict_title:"Chyba připojení VPN",extension_conflict_text_1:"Ostatní rozšíření prohlížeče blokují přístup k nastavení proxy serveru pro Planet VPN.",extension_conflict_text_2:"Zakažte prosím další rozšíření, která mohou ovládat nastavení proxy ve vašem prohlížeči.",extension_conflict_button_chrome:"Zakázat další rozšíření",extension_conflict_button_firefox:"Jak zakázat rozšíření?",ads_interstitial_goto:"Jít",ads_interstitial_close:"Zpět k VPN",navigation_menu_settings:"Nastavení",navigation_menu_